<template>
    <div>
        <div style="margin-bottom: 20px">
            <el-input style="width: 240px" placeholder="请输入名称" v-model="params.name"></el-input>
            <el-button style="margin-left: 5px" type="primary" round @click="load"><i class="el-icon-search" ></i>搜索</el-button>
            <el-button style="margin-left: 5px" type="info" round @click="reset"><i class="el-icon-refresh-right" ></i>重置</el-button>
            <el-button style="margin-left: 5px" type="warning" round @click="add"><i class="el-icon-star-off" ></i>添加</el-button>
        </div>
        <el-table :data="tableData" stripe size="medium" :border="true" >
            <el-table-column prop="username" label="用户编号" ></el-table-column>
            <el-table-column prop="name" label="名称" ></el-table-column>
            <el-table-column prop="age" label="年龄" ></el-table-column>
            <el-table-column prop="phone" label="电话号码" ></el-table-column>
            <el-table-column prop="sex" label="性别"></el-table-column>
            <el-table-column label="操作" >
                <template v-slot="scope">
                    <!--                scope.row就是当前行数据-->
                    <el-button style="background-color: darkcyan; color: white"  icon="el-icon-edit"  @click="$router.push('/editUser?id=' + scope.row.id)">编辑</el-button>
                    <el-popconfirm
                            style="margin-left: 5px"
                            title="您确定删除吗？"
                            @confirm="del(scope.row.id)"
                    >
                        <el-button type="danger" slot="reference"  icon="el-icon-delete">删除</el-button>
                    </el-popconfirm>
<!--                    @click执行跳转页面和将数据带过去的操作，得到了id,需要后台UserController.java提供根据id查询的接口-->
                </template>
            </el-table-column>
        </el-table>

        <!--      分页-->
        <div style="margin-top: 20px">
            <el-pagination
                    background
                    :current-page="params.pageNum"
                    :page-size="params.pageSize"
                    layout="prev, pager, next"
                    @current-change="handleCurrentChange"
                    :total="total">
                <!--              tableData.length为当前表格的总个数-->
            </el-pagination>
        </div>
    </div>
</template>

<script>
    import request from "@/utils/request";

    export default {
        name: 'UserList',
        data(){
            return{
                tableData:[

                ],
                total: 0,
                params: {
                    pageNum: 1,
                    pageSize: 5,
                    name: '',
                },
                rules:{

                }

            }
        },
        created() {
            this.load()

        },
        methods: {
            load() {
                request.get('/user/page',{params: this.params}).then(res =>{
                    if(res.code === '200'){
                        this.tableData = res.data.list
                        this.total = res.data.total

                    }

                })
            },
            reset(){
                this.params = {
                    pageNum: 1,
                    pageSize: 10,
                    name: '',

                }
                this.load()
            },

            handleCurrentChange(pageNum){
                //点击分页按钮触发分页
                this.params.pageNum = pageNum;
                this.load();
            },
            del(id){
                request.delete("/user/delete/"+id).then(res =>{
                    if(res.code === '200'){
                        this.$notify.success('删除成功');
                        this.load();
                    //    this.load()用来从新加载数据
                    }else{
                        this.$notify.error(res.msg)
                    }
                })
            },
            add(){
                this.$router.push('addUser');
            }

        }


    }
</script>

